const SQ=String.fromCharCode(39);
const q=s=>(s===null||s===undefined||s==='')?'NULL':SQ+String(s).split(SQ).join(SQ+SQ)+SQ;
const num=s=>{if(s==null||s==='')return null;const v=parseFloat(String(s).replace(/[^0-9.\-]/g,''));return isNaN(v)?null:v;};
const col=(cv,id)=>{const c=(cv||[]).find(x=>x.id===id);return (c&&c.text)?c.text:null;};
const rows=(node)=>{const b=((($(node).first().json||{}).data||{}).boards)||[];return (b[0]&&b[0].items_page&&b[0].items_page.items)?b[0].items_page.items:[];};

// Refresh ONLY accounts already in the brain. New/dormant accounts are NOT imported here —
// a new account is created on demand by the Main Pipeline when its first call arrives.
const existing=$('Accounts in DB').all().map(r=>r.json).filter(a=>a&&a.name);
if(!existing.length){return [{json:{sql:"SELECT 'reconcile skipped: no active accounts to refresh' AS note;",accounts:0,projects:0,associates:0,statements:0}}];}
const findAcc=(name)=>{const nl=(name||'').toLowerCase();if(!nl)return null;return existing.find(a=>{const al=a.name.toLowerCase();return al===nl||al.includes(nl)||nl.includes(al);})||null;};

const sowItems=rows('Monday: SOWs');
const cadItems=rows('Monday: cadence');
const asItems=rows('Monday: associates');
if(!sowItems.length){return [{json:{sql:"SELECT 'reconcile skipped: no Monday SOW data (fail-safe)' AS note;",accounts:existing.length,projects:0,associates:0,statements:0}}];}

const stmts=[];
let pj=0, asc=0;

// 0) Client-name directory (names ONLY — the lazy model is unchanged): every group title on the
// SOW board is a client name. This lets the Watcher recognise a client the brain hasn't met yet;
// the account row + its SOWs are still created on demand by the Main Pipeline on first call.
const dseen={};let dnames=0;
for(const it of sowItems){const g=(it.group&&it.group.title)?String(it.group.title).trim():'';const gl=g.toLowerCase();if(!g||dseen[gl])continue;dseen[gl]=1;dnames++;stmts.push("INSERT INTO client_directory (name,source,last_seen) VALUES ("+q(g)+",'monday_sow',now()) ON CONFLICT (name) DO UPDATE SET last_seen=now();");}

// 1) Freshness stamp + pod, for every already-tracked account.
const groups={};
for(const it of cadItems){const g=(it.group&&it.group.title)?it.group.title:'';if(!g)continue;const pod=col(it.column_values,'dropdown8__1');const dm=col(it.column_values,'people__1');if(!groups[g])groups[g]={pod:null,dm:null};if(pod&&!groups[g].pod)groups[g].pod=pod;if(dm&&!groups[g].dm)groups[g].dm=dm;}
const gkeys=Object.keys(groups);
for(const a of existing){
  stmts.push("UPDATE accounts SET last_verified=now() WHERE id="+q(a.id)+";");
  const gk=gkeys.find(k=>{const kl=k.toLowerCase(),al=a.name.toLowerCase();return (kl.includes(al)||al.includes(kl))&&groups[k].pod;});
  if(gk){stmts.push("UPDATE accounts SET pod="+q(groups[gk].pod)+" WHERE id="+q(a.id)+" AND pod IS DISTINCT FROM "+q(groups[gk].pod)+";");}
}

// 2) Projects + SOW numbers + DM — ONLY for SOWs whose account is already tracked.
for(const it of sowItems){
  const acc=findAcc((it.group&&it.group.title)?it.group.title:'');
  if(!acc)continue;
  pj++;
  let sum=0,any=false;(it.subitems||[]).forEach(su=>{const v=num(col(su.column_values,'numbers'));if(v!==null){sum+=v;any=true;}});
  const val=any?Math.round(sum*100)/100:null;
  const cv=it.column_values;
  stmts.push("INSERT INTO projects (monday_item_id,name,account_name,account_id,sow_value,start_date,end_date,sow_status,commercial_model,last_verified) VALUES ("+q(it.id)+","+q(it.name)+","+q(acc.name)+","+q(acc.id)+","+(val===null?'NULL':val)+","+q(col(cv,'date'))+"::date,"+q(col(cv,'date6'))+"::date,"+q(col(cv,'sow_status'))+","+q(col(cv,'status'))+",now()) ON CONFLICT (monday_item_id) DO UPDATE SET name=EXCLUDED.name,account_id=EXCLUDED.account_id,sow_value=EXCLUDED.sow_value,start_date=EXCLUDED.start_date,end_date=EXCLUDED.end_date,sow_status=EXCLUDED.sow_status,commercial_model=EXCLUDED.commercial_model,last_verified=now() WHERE projects.sow_value IS DISTINCT FROM EXCLUDED.sow_value OR projects.sow_status IS DISTINCT FROM EXCLUDED.sow_status OR projects.start_date IS DISTINCT FROM EXCLUDED.start_date OR projects.end_date IS DISTINCT FROM EXCLUDED.end_date OR projects.commercial_model IS DISTINCT FROM EXCLUDED.commercial_model;");
  const toks=(it.name||'').toLowerCase().split(/[^a-z0-9]+/).filter(w=>w.length>=3);
  let gk=gkeys.find(k=>{const kl=k.toLowerCase();return kl.includes(acc.name.toLowerCase())&&toks.some(t=>kl.includes(t))&&groups[k].dm;});
  if(!gk)gk=gkeys.find(k=>toks.some(t=>k.toLowerCase().includes(t))&&groups[k].dm);
  if(gk){stmts.push("UPDATE projects SET delivery_manager_name="+q(groups[gk].dm)+" WHERE monday_item_id="+q(it.id)+" AND delivery_manager_name IS DISTINCT FROM "+q(groups[gk].dm)+";");}
}

// 3) Consultants — ONLY for accounts already tracked.
for(const it of asItems){
  const cv=it.column_values||[];const cname=col(cv,'client_name6')||'';const acc=findAcc(cname);
  if(!acc)continue;
  asc++;
  const team=col(cv,'team');const placement=col(cv,'status0');
  stmts.push("INSERT INTO associates (monday_item_id,name,account_id,account_name,project_or_programme,placement_status,last_verified) VALUES ("+q(it.id)+","+q(it.name)+","+q(acc.id)+","+q(acc.name)+","+q(team)+","+q(placement)+",now()) ON CONFLICT (monday_item_id) DO UPDATE SET account_id=EXCLUDED.account_id,project_or_programme=EXCLUDED.project_or_programme,placement_status=EXCLUDED.placement_status,last_verified=now() WHERE associates.placement_status IS DISTINCT FROM EXCLUDED.placement_status OR associates.project_or_programme IS DISTINCT FROM EXCLUDED.project_or_programme OR associates.account_id IS DISTINCT FROM EXCLUDED.account_id;");
}

const sql=stmts.length?stmts.join(' '):"SELECT 'nothing to reconcile' AS note;";
return [{json:{sql,accounts:existing.length,projects:pj,associates:asc,statements:stmts.length}}];
